input.command:
cd /root/capsule/.claude/projects/-root-capsule && for f in $(ls -t *.jsonl); do
  first_user=$(grep -m1 '"type":"user"' "$f" 2>/dev/null | python3 -c "import sys,json; 
try:
    d=json.loads(sys.stdin.read())
    m=d.get('message',{}).get('content','')
    if isinstance(m,list): m=' '.join(x.get('text','') for x in m if isinstance(x,dict))
    print(str(m)[:120].replace('\n',' '))
except: print('')" 2>/dev/null)
  mtime=$(stat -c '%y' "$f" | cut -d. -f1)
  size=$(stat -c '%s' "$f")
  printf '%s  %8d  %s\n    %s\n' "$mtime" "$size" "${f%.jsonl}" "$first_user"
done
